import { useNavigate } from 'react-router-dom';
import styled from 'styled-components';
import Box from '@mui/material/Box';
import Typography from '@mui/material/Typography';
import Container from '@mui/material/Container';

import movie from '../Assets/movie.png'
import workout from '../Assets/workout.png'
import commandLine from '../Assets/commandLine.png'

const BoxWithHover = styled(Box)`
  transition: .5s;
  &:hover {
    transform: scale(1.05); /* Enlarge the image on hover */
  }
`;

const projectItem = (image, name, func) => {
  return (
    <Container
      maxWidth='none'
      onClick={func}
      sx={{
        display: 'flex', 
            flexDirection: {xs:'column', sm:'row'}, 
        // flexDirection: 'row', 
        alignItems: 'center',
        // justifyContent: 'center',
        width: '100%',
        mx: 'auto',
        // mb: '25vh',
        cursor: 'pointer'
      }}       
    >
      <BoxWithHover>
        <Box 
          component='img'
          src={image}
          alt={`${name} logo`}
          sx={{
            height: '10vw',
            mr: 2,
          }}
        />
      </BoxWithHover>
      {/* <Typography sx={{ display: 'flex', alignItems: 'center', flexDirection: 'row' }} variant='h3'>{name}</Typography> */}
      <Typography sx={{ display: 'flex', alignItems: 'center', justifyContent: 'center', justifyItems: 'center', height: '100%' }} variant='h3'>flat & iron abs</Typography>
    </Container>
  );
};

function Projects () {
    const navigate = useNavigate();
    const reroute = (path) => {
        return () => navigate(path);
        // return () => window.open(path, '_blank');
    };

    return (
        <Container
          maxWidth='none'
          sx={{
            display: 'flex', 
            flexDirection: 'column', 

            alignItems: 'center',
            width: '100%',
            mx: 'auto',
            mb: '25vh'
          }}        
        >
            <Typography 
              id='projects'
              variant='h2' 
              my={4}
            >
              Projects
            </Typography>
            <Box sx={{ display: 'flex', flexDirection: {xs:'column', sm:'column'}}}>
              {/* {projectItem(movie, 'Topher Emby', reroute('/TopherEmby') )}
              {projectItem(commandLine, 'OnlyKyles', reroute('/OnlyKyles') )}
              {projectItem(workout, 'Flat & Iron Abs', reroute('/FlatIronAbs') )} */}
              {projectItem(movie, 'Topher Emby')}
              {projectItem(commandLine, 'OnlyKyles')}
              {projectItem(workout, 'Flat & Iron Abs')}
            </Box>
        </Container>
    );
}

export default Projects;
